			CheckBunny();
			if (Lang.lang > 1)
			{
				Lang.setLang(true);
			}
			Lang.setLang();
			if (Lang.lang == 0)
			{
				menuMode = 1212;
			}
			SetTitle();
			OpenRecent();
			Star.SpawnStars();
			WorldGen.RandomWeather();
			foreach (DisplayMode supportedDisplayMode in GraphicsAdapter.DefaultAdapter.SupportedDisplayModes)
			{
				if (supportedDisplayMode.Width < minScreenW || supportedDisplayMode.Height < minScreenH || supportedDisplayMode.Width > maxScreenW || supportedDisplayMode.Height > maxScreenH)
				{
					continue;
				}
				bool flag = true;
				for (int num24 = 0; num24 < numDisplayModes; num24++)
				{
					if (supportedDisplayMode.Width == displayWidth[num24] && supportedDisplayMode.Height == displayHeight[num24])
					{
						flag = false;
						break;
					}
				}
				if (flag)
				{
					displayHeight[numDisplayModes] = supportedDisplayMode.Height;
					displayWidth[numDisplayModes] = supportedDisplayMode.Width;
					numDisplayModes++;
				}
			}
			if (autoJoin)
			{
				LoadPlayers();
				menuMode = 1;
				menuMultiplayer = true;
			}
			fpsTimer.Start();
			updateTimer.Start();
			TempRealtimeLogger.Info("Main.Initialize", "END");
		}

