		public static void stopMoonEvent()
		{
			if (pumpkinMoon)
			{
				pumpkinMoon = false;
				if (netMode != 1)
				{
					NPC.waveKills = 0f;
					NPC.waveCount = 0;
				}
			}
			if (snowMoon)
			{
				snowMoon = false;
				if (netMode != 1)
				{
					NPC.waveKills = 0f;
					NPC.waveCount = 0;
				}
			}
		}

		public static void startPumpkinMoon()
		{
			pumpkinMoon = true;
			snowMoon = false;
			bloodMoon = false;
			if (netMode != 1)
			{
				NPC.waveKills = 0f;
				NPC.waveCount = 1;
				string text = "First Wave: " + npcName[305];
				if (netMode == 0)
				{
					NewText(text, 175, 75);
				}
				else if (netMode == 2)
				{
					NetMessage.SendData(25, -1, -1, text, 255, 175f, 75f, 255f);
				}
			}
		}

		public static void startSnowMoon()
		{
			snowMoon = true;
			pumpkinMoon = false;
			bloodMoon = false;
			if (netMode != 1)
			{
				NPC.waveKills = 0f;
				NPC.waveCount = 1;
				string text = "First Wave: Zombie Elf and Gingerbread Man";
				if (netMode == 0)
				{
					NewText(text, 175, 75);
				}
				else if (netMode == 2)
				{
					NetMessage.SendData(25, -1, -1, text, 255, 175f, 75f, 255f);
				}
			}
		}

		protected void UpdateMusic()
		{
			if (musicVolume == 0f)
			{
				curMusic = 0;
			}
			try
			{
				if (dedServ)
				{
					return;
				}
				if (curMusic > 0)
				{
					if (!base.IsActive)
					{
						if (!music[curMusic].IsPaused && music[curMusic].IsPlaying)
						{
							try
							{
								music[curMusic].Pause();
							}
							catch
							{
							}
						}
					}
					else if (music[curMusic].IsPaused)
					{
						music[curMusic].Resume();
					}
				}
				if (!base.IsActive)
				{
					if (music[28].IsPaused || !music[28].IsPlaying)
					{
						return;
					}
					try
					{
						music[28].Pause();
						return;
					}
					catch
					{
						return;
					}
				}
				bool flag = false;
				bool flag2 = false;
				bool flag3 = false;
				bool flag4 = false;
				bool flag5 = false;
				bool flag6 = false;
				Rectangle rectangle = new Rectangle((int)screenPosition.X, (int)screenPosition.Y, screenWidth, screenHeight);
				int num = 5000;
				for (int i = 0; i < 200; i++)
				{
					if (!npc[i].active)
					{
						continue;
					}
					if (npc[i].type == 262 || npc[i].type == 263 || npc[i].type == 264)
					{
						Rectangle value = new Rectangle((int)(npc[i].position.X + (float)(npc[i].width / 2)) - num, (int)(npc[i].position.Y + (float)(npc[i].height / 2)) - num, num * 2, num * 2);
						if (rectangle.Intersects(value))
						{
							flag6 = true;
							break;
						}
					}
					else if (npc[i].type == 134 || npc[i].type == 143 || npc[i].type == 144 || npc[i].type == 145 || npc[i].type == 266)
					{
						Rectangle value2 = new Rectangle((int)(npc[i].position.X + (float)(npc[i].width / 2)) - num, (int)(npc[i].position.Y + (float)(npc[i].height / 2)) - num, num * 2, num * 2);
						if (rectangle.Intersects(value2))
						{
							flag3 = true;
							break;
						}
					}
					else if ((npc[i].type >= 212 && npc[i].type <= 216) || npc[i].type == 245)
					{
						Rectangle value3 = new Rectangle((int)(npc[i].position.X + (float)(npc[i].width / 2)) - num, (int)(npc[i].position.Y + (float)(npc[i].height / 2)) - num, num * 2, num * 2);
						if (rectangle.Intersects(value3))
						{
							flag4 = true;
							break;
						}
					}
					else if (npc[i].type == 113 || npc[i].type == 114 || npc[i].type == 125 || npc[i].type == 126)
					{
						Rectangle value4 = new Rectangle((int)(npc[i].position.X + (float)(npc[i].width / 2)) - num, (int)(npc[i].position.Y + (float)(npc[i].height / 2)) - num, num * 2, num * 2);
						if (rectangle.Intersects(value4))
						{
							flag2 = true;
							break;
						}
					}
					else if (npc[i].type == 222)
					{
						Rectangle value5 = new Rectangle((int)(npc[i].position.X + (float)(npc[i].width / 2)) - num, (int)(npc[i].position.Y + (float)(npc[i].height / 2)) - num, num * 2, num * 2);
						if (rectangle.Intersects(value5))
						{
							flag5 = true;
							break;
						}
					}
					else if (npc[i].boss || npc[i].type == 13 || npc[i].type == 14 || npc[i].type == 15 || npc[i].type == 134 || npc[i].type == 26 || npc[i].type == 27 || npc[i].type == 28 || npc[i].type == 29 || npc[i].type == 111)
					{
						Rectangle value6 = new Rectangle((int)(npc[i].position.X + (float)(npc[i].width / 2)) - num, (int)(npc[i].position.Y + (float)(npc[i].height / 2)) - num, num * 2, num * 2);
						if (rectangle.Intersects(value6))
						{
							flag = true;
							break;
						}
					}
				}
				int num2 = (int)((screenPosition.X + (float)(screenWidth / 2)) / 16f);
				if (musicVolume == 0f)
				{
					newMusic = 0;
				}
				else if (gameMenu)
				{
					if (netMode != 2)
					{
						newMusic = 6;
					}
					else
					{
						newMusic = 0;
					}
				}
				else
				{
					float num3 = maxTilesX / 4200;
					num3 *= num3;
					float num4 = (float)((double)((screenPosition.Y + (float)(screenHeight / 2)) / 16f - (65f + 10f * num3)) / (worldSurface / 5.0));
					if (flag6)
					{
						newMusic = 24;
					}
					else if (flag2)
					{
						newMusic = 12;
					}
					else if (flag)
					{
						newMusic = 5;
					}
					else if (flag3)
					{
						newMusic = 13;
					}
					else if (flag4)
					{
						newMusic = 17;
					}
					else if (flag5)
					{
						newMusic = 25;
					}
					else if (player[myPlayer].position.Y > (float)((maxTilesY - 200) * 16))
					{
						newMusic = 2;
					}
					else if (eclipse && (double)player[myPlayer].position.Y < worldSurface * 16.0 + (double)(screenHeight / 2))
					{
						newMusic = 27;
					}
					else if (num4 < 1f)
					{
						newMusic = 15;
					}
					else if (tile[(int)(player[myPlayer].Center().X / 16f), (int)(player[myPlayer].Center().Y / 16f)].wall == 87)
					{
						newMusic = 26;
					}
					else if ((bgStyle == 9 && (double)player[myPlayer].position.Y < worldSurface * 16.0 + (double)(screenHeight / 2)) || ugBack == 2)
					{
						newMusic = 29;
					}
					else if (player[myPlayer].zoneEvil)
					{
						if ((double)player[myPlayer].position.Y > worldSurface * 16.0 + (double)(screenHeight / 2))
						{
							newMusic = 10;
						}
						else
						{
							newMusic = 8;
						}
					}
					else if (player[myPlayer].zoneBlood)
					{
						if ((double)player[myPlayer].position.Y > worldSurface * 16.0 + (double)(screenHeight / 2))
						{
							newMusic = 33;
						}
						else
						{
							newMusic = 16;
						}
					}
					else if (player[myPlayer].zoneDungeon)
					{
						newMusic = 23;
					}
					else if (player[myPlayer].zoneMeteor)
					{
						newMusic = 2;
					}
					else if (player[myPlayer].zoneJungle)
					{
						newMusic = 7;
					}
					else if (player[myPlayer].zoneSnow)
					{
						if ((double)player[myPlayer].position.Y > worldSurface * 16.0 + (double)(screenHeight / 2))
						{
							newMusic = 20;
						}
						else
						{
							newMusic = 14;
						}
					}
					else if ((double)player[myPlayer].position.Y > worldSurface * 16.0 + (double)(screenHeight / 2))
					{
						if (player[myPlayer].zoneHoly)
						{
							newMusic = 11;
						}
						else
						{
							if (ugMusic == 0)
							{
								ugMusic = 4;
							}
							if (!music[4].IsPlaying && !music[31].IsPlaying)
							{
								if (musicFade[4] == 1f)
								{
									musicFade[31] = 1f;
								}
								if (musicFade[31] == 1f)
								{
									musicFade[4] = 1f;
								}
								switch (rand.Next(2))
								{
								case 0:
									ugMusic = 4;
									musicFade[31] = 0f;
									break;
								case 1:
									ugMusic = 31;
									musicFade[4] = 0f;
									break;
								}
							}
							newMusic = ugMusic;
						}
					}
					else if (dayTime && player[myPlayer].zoneHoly)
					{
						if (cloudAlpha > 0f && !gameMenu)
						{
							newMusic = 19;
						}
						else
						{
							newMusic = 9;
						}
					}
					else if ((double)(screenPosition.Y / 16f) < worldSurface + 10.0 && (num2 < 380 || num2 > maxTilesX - 380))
					{
						newMusic = 22;
					}
					else if (sandTiles > 1000)
					{
						newMusic = 21;
					}
					else if (dayTime)
					{
						if (cloudAlpha > 0f && !gameMenu)
						{
							newMusic = 19;
						}
						else
						{
							if (dayMusic == 0)
							{
								dayMusic = 1;
							}
							if (!music[1].IsPlaying && !music[18].IsPlaying)
							{
								switch (rand.Next(2))
								{
								case 0:
									dayMusic = 1;
									break;
								case 1:
									dayMusic = 18;
									break;
								}
							}
							newMusic = dayMusic;
						}
					}
					else if (!dayTime)
					{
						if (bloodMoon)
						{
							newMusic = 2;
						}
						else if (cloudAlpha > 0f && !gameMenu)
						{
							newMusic = 19;
						}
						else
						{
							newMusic = 3;
