				time += 86.4;
				if (!dayTime)
				{
					if (time > 32400.0)
					{
						bloodMoon = false;
						time = 0.0;
						dayTime = true;
						moonPhase++;
						if (moonPhase >= 8)
						{
							moonPhase = 0;
						}
					}
				}
				else if (time > 54000.0)
				{
					time = 0.0;
					dayTime = false;
				}
			}
			else if (netMode == 1)
			{
				UpdateTime();
			}
		}

