				}
				spriteBatch.Draw(hbTexture1, new Vector2(num3 - screenPosition.X + (float)(num2 - 2) * scale, num4 - screenPosition.Y), new Rectangle(32, 0, 2, hbTexture1.Height), color, 0f, new Vector2(0f, 0f), scale, SpriteEffects.None, 0f);
			}
