		private static bool AccCheck(Item newItem, int slot)
		{
			if (player[myPlayer].armor[slot].IsTheSameAs(newItem))
			{
				return false;
			}
			if (player[myPlayer].armor[slot].wingSlot > 0 && newItem.wingSlot > 0)
			{
				return false;
			}
			for (int i = 0; i < player[myPlayer].armor.Length; i++)
			{
				if (slot < 8 && i < 8)
				{
					if (newItem.wingSlot > 0 && player[myPlayer].armor[i].wingSlot > 0)
					{
						return true;
					}
				}
				else if (slot >= 8 && i >= 8 && newItem.wingSlot > 0 && player[myPlayer].armor[i].wingSlot > 0)
				{
					return true;
				}
				if (newItem.IsTheSameAs(player[myPlayer].armor[i]))
				{
					return true;
				}
			}
			return false;
		}

		public static Item dyeSwap(Item newItem)
		{
			if (newItem.dye <= 0)
			{
				return newItem;
			}
			Item item = newItem;
			for (int i = 0; i < 8; i++)
			{
				if (player[myPlayer].dye[i].type == 0)
				{
					dyeSlotCount = i;
					break;
				}
			}
			if (dyeSlotCount >= 8)
			{
				dyeSlotCount = 0;
			}
			if (dyeSlotCount < 0)
			{
				dyeSlotCount = 7;
			}
			item = player[myPlayer].dye[dyeSlotCount].Clone();
			player[myPlayer].dye[dyeSlotCount] = newItem.Clone();
			dyeSlotCount++;
			if (dyeSlotCount >= 8)
			{
				accSlotCount = 0;
			}
			PlaySound(7);
			Recipe.FindRecipes();
			return item;
		}

		public static Item armorSwap(Item newItem)
		{
			for (int i = 0; i < player[myPlayer].armor.Length; i++)
			{
				if (newItem.IsTheSameAs(player[myPlayer].armor[i]))
				{
					accSlotCount = i;
				}
			}
			if (newItem.headSlot == -1 && newItem.bodySlot == -1 && newItem.legSlot == -1 && !newItem.accessory)
			{
				return newItem;
			}
			Item result = newItem;
			if (newItem.headSlot != -1)
			{
				result = player[myPlayer].armor[0].Clone();
				player[myPlayer].armor[0] = newItem.Clone();
			}
			else if (newItem.bodySlot != -1)
			{
				result = player[myPlayer].armor[1].Clone();
				player[myPlayer].armor[1] = newItem.Clone();
			}
			else if (newItem.legSlot != -1)
			{
				result = player[myPlayer].armor[2].Clone();
				player[myPlayer].armor[2] = newItem.Clone();
			}
			else if (newItem.accessory)
			{
				for (int j = 3; j < 8; j++)
				{
					if (player[myPlayer].armor[j].type == 0)
					{
						accSlotCount = j - 3;
						break;
					}
				}
				for (int k = 0; k < player[myPlayer].armor.Length; k++)
				{
					if (newItem.IsTheSameAs(player[myPlayer].armor[k]))
					{
						accSlotCount = k - 3;
					}
					if (k < 8 && newItem.wingSlot > 0 && player[myPlayer].armor[k].wingSlot > 0)
					{
						accSlotCount = k - 3;
					}
				}
				if (accSlotCount >= 5)
				{
					accSlotCount = 0;
				}
				if (accSlotCount < 0)
				{
					accSlotCount = 4;
				}
				result = player[myPlayer].armor[3 + accSlotCount].Clone();
				player[myPlayer].armor[3 + accSlotCount] = newItem.Clone();
				accSlotCount++;
				if (accSlotCount >= 5)
				{
					accSlotCount = 0;
				}
			}
			PlaySound(7);
			Recipe.FindRecipes();
			return result;
		}

		public static void MoveCoins(Item[] pInv, Item[] cInv)
		{
			int[] array = new int[4];
			List<int> list = new List<int>();
			List<int> list2 = new List<int>();
			bool flag = false;
			int[] array2 = new int[Chest.maxItems];
			for (int i = 0; i < cInv.Length; i++)
			{
				array2[i] = -1;
				if (cInv[i].stack < 1 || cInv[i].type < 1)
				{
					list2.Add(i);
					cInv[i] = new Item();
				}
				if (cInv[i] != null && cInv[i].stack > 0)
				{
					int num = 0;
					if (cInv[i].type == 71)
					{
						num = 1;
					}
					if (cInv[i].type == 72)
					{
						num = 2;
					}
					if (cInv[i].type == 73)
					{
						num = 3;
					}
					if (cInv[i].type == 74)
					{
						num = 4;
					}
					array2[i] = num - 1;
					if (num > 0)
					{
						array[num - 1] += cInv[i].stack;
						list2.Add(i);
						cInv[i] = new Item();
						flag = true;
					}
				}
			}
			if (!flag)
			{
				return;
			}
			PlaySound(7);
			for (int j = 0; j < pInv.Length; j++)
			{
				if (j != 58 && pInv[j] != null && pInv[j].stack > 0)
				{
