		protected bool FullTile(int x, int y)
		{
			if (Main.tile[x - 1, y].blockType() != 0 || Main.tile[x + 1, y].blockType() != 0)
			{
				return false;
			}
			Tile tile = Main.tile[x, y];
			if (tile == null)
			{
				return false;
			}
			if (tile.active())
			{
				if (tile.type == 10 || tile.type == 54 || tile.type == 138 || tile.type == 191 || tile.type == 137 || tile.type == 328)
				{
					return false;
				}
				if (tileSolid[tile.type] && !tileSolidTop[tile.type])
				{
					int frameX = tile.frameX;
					int frameY = tile.frameY;
					if (tileLargeFrames[tile.type] == 1)
					{
						if (frameY == 18 || frameY == 108)
						{
							if (frameX >= 18 && frameX <= 54)
							{
								return true;
							}
							if (frameX >= 108 && frameX <= 144)
							{
								return true;
							}
						}
					}
					else if (frameY == 18)
					{
						if (frameX >= 18 && frameX <= 54)
						{
							return true;
						}
						if (frameX >= 108 && frameX <= 144)
						{
							return true;
						}
					}
					else if (frameY >= 90 && frameY <= 196)
					{
						if (frameX <= 70)
						{
							return true;
						}
						if (frameX >= 144 && frameX <= 232)
						{
							return true;
						}
					}
				}
			}
			return false;
		}

