					if (tile[j, i].wire3() && Lighting.Brightness(j, i) > 0f)
					{
						Rectangle rectangle3 = new Rectangle(0, 0, 16, 16);
						bool flag9 = tile[j, i - 1].wire3();
						bool flag10 = tile[j, i + 1].wire3();
						bool flag11 = tile[j - 1, i].wire3();
						bool flag12 = tile[j + 1, i].wire3();
						rectangle3 = (flag9 ? (flag10 ? (flag11 ? ((!flag12) ? new Rectangle(54, 0, 16, 16) : new Rectangle(18, 18, 16, 16)) : ((!flag12) ? new Rectangle(0, 0, 16, 16) : new Rectangle(36, 0, 16, 16))) : (flag11 ? ((!flag12) ? new Rectangle(54, 18, 16, 16) : new Rectangle(0, 18, 16, 16)) : ((!flag12) ? new Rectangle(36, 36, 16, 16) : new Rectangle(36, 18, 16, 16)))) : (flag10 ? (flag11 ? ((!flag12) ? new Rectangle(72, 18, 16, 16) : new Rectangle(72, 0, 16, 16)) : ((!flag12) ? new Rectangle(18, 36, 16, 16) : new Rectangle(0, 36, 16, 16))) : (flag11 ? ((!flag12) ? new Rectangle(54, 36, 16, 16) : new Rectangle(18, 0, 16, 16)) : ((!flag12) ? new Rectangle(0, 54, 16, 16) : new Rectangle(72, 36, 16, 16)))));
						Color color3 = Lighting.GetColor(j, i);
						int num7 = 1;
						float num8 = 1f;
						if (tile[j, i].wire())
						{
							num7++;
						}
						if (tile[j, i].wire2())
						{
							num7++;
						}
						num8 = 1f / (float)num7;
						byte r2 = (byte)((float)(int)color3.R * num8);
						byte g2 = (byte)((float)(int)color3.G * num8);
						byte b3 = (byte)((float)(int)color3.B * num8);
						byte b4 = (byte)((float)(int)color3.A * num8);
						color3 = new Color(r2, g2, b3, b4);
						spriteBatch.Draw(wire3Texture, new Vector2(j * 16 - (int)screenPosition.X, i * 16 - (int)screenPosition.Y) + vector, rectangle3, color3, 0f, default(Vector2), 1f, SpriteEffects.None, 0f);
					}
					if (tile[j, i].actuator() && Lighting.Brightness(j, i) > 0f)
					{
						Color color4 = Lighting.GetColor(j, i);
						spriteBatch.Draw(actuatorTexture, new Vector2(j * 16 - (int)screenPosition.X, i * 16 - (int)screenPosition.Y) + vector, new Rectangle(0, 0, actuatorTexture.Width, actuatorTexture.Height), color4, 0f, default(Vector2), 1f, SpriteEffects.None, 0f);
					}
				}
			}
			TimeLogger.DetailedDrawTime(34);
		}

		public static int GetTreeStyle(int X)
		{
			int num = 0;
			num = ((X <= treeX[0]) ? treeStyle[0] : ((X <= treeX[1]) ? treeStyle[1] : ((X > treeX[2]) ? treeStyle[3] : treeStyle[2])));
			switch (num)
			{
			case 0:
				return 0;
			case 5:
				return 10;
			default:
				return 5 + num;
			}
		}

		protected void lookForColorTiles()
		{
			int num = (int)(screenPosition.X / 16f - 2f);
			int num2 = (int)((screenPosition.X + (float)screenWidth) / 16f) + 3;
			int num3 = (int)(screenPosition.Y / 16f - 2f);
			int num4 = (int)((screenPosition.Y + (float)screenHeight) / 16f) + 3;
			if (num < 1)
			{
				num = 1;
			}
			if (num2 > maxTilesX - 2)
			{
				num = maxTilesX - 2;
			}
			for (int i = num; i < num2; i++)
			{
				if (i <= 0)
				{
					continue;
				}
				for (int j = num3; j < num4; j++)
				{
					if (tile[i, j] != null)
					{
						if (tile[i, j].active() && tile[i, j].color() > 0)
						{
							tileColorCheck(tile[i, j].type, tile[i, j].color());
						}
						if (tile[i, j].wall > 0 && tile[i, j].wallColor() > 0)
						{
							wallColorCheck(tile[i, j].wall, tile[i, j].wallColor());
						}
					}
				}
			}
			for (int k = 0; k < numTreeStyles; k++)
			{
				for (int l = 0; l < numTileColors; l++)
				{
					if (checkTreeAlt[k, l])
					{
						treeColorCheck(k, l);
						checkTreeAlt[k, l] = false;
					}
				}
			}
		}

		protected void tileColorCheck(int t, int c)
		{
			LoadTiles(t);
			if (c >= numTileColors)
			{
				return;
			}
			if (!tileAltTextureInit[t, c])
			{
				tileAltTexture[t, c] = new RenderTarget2D(base.GraphicsDevice, tileTexture[t].Width, tileTexture[t].Height, false, base.GraphicsDevice.PresentationParameters.BackBufferFormat, DepthFormat.Depth24, 0, RenderTargetUsage.PreserveContents);
				tileAltTextureInit[t, c] = true;
			}
			if (tileAltTexture[t, c].IsContentLost)
			{
				tileAltTextureDrawn[t, c] = false;
			}
			if (!tileAltTextureDrawn[t, c])
			{
				base.GraphicsDevice.SetRenderTarget(tileAltTexture[t, c]);
				base.GraphicsDevice.Clear(Color.Transparent);
				spriteBatch.Begin(SpriteSortMode.Immediate, BlendState.AlphaBlend);
				if (c >= 28)
				{
					int index = 40 + c - 28;
					tileShader.CurrentTechnique.Passes[index].Apply();
				}
				else if (c > 0 && c < 13 && (t == 0 || t == 2 || t == 5 || t == 23 || t == 59 || t == 60 || t == 70 || t == 109 || t == 199))
				{
					int index2 = c + 27;
					tileShader.CurrentTechnique.Passes[index2].Apply();
				}
				else
				{
					tileShader.CurrentTechnique.Passes[c].Apply();
				}
				spriteBatch.Draw(tileTexture[t], new Rectangle(0, 0, tileTexture[t].Width, tileTexture[t].Height), Color.White);
				spriteBatch.End();
				base.GraphicsDevice.SetRenderTarget(null);
				tileAltTextureDrawn[t, c] = true;
			}
		}

