		protected void DrawSurfaceBG()
		{
			if (!mapFullscreen && (double)screenPosition.Y < worldSurface * 16.0 + 16.0)
			{
				for (int i = 0; i < 200; i++)
				{
					if (cloud[i].active && cloud[i].scale < 1f)
					{
						Color color = cloud[i].cloudColor(bgColor);
						float num = cloud[i].scale * 0.8f;
						float num2 = (cloud[i].scale + 1f) / 2f * 0.9f;
						color.R = (byte)((float)(int)color.R * num);
						color.G = (byte)((float)(int)color.G * num2);
						atmo = 1f;
						if (atmo < 1f)
						{
							color.R = (byte)((float)(int)color.R * atmo);
							color.G = (byte)((float)(int)color.G * atmo);
							color.B = (byte)((float)(int)color.B * atmo);
							color.A = (byte)((float)(int)color.A * atmo);
						}
						float num3 = cloud[i].position.Y * ((float)screenHeight / 600f);
						num3 = cloud[i].position.Y + (float)(int)((double)(0f - screenPosition.Y + screenOff / 2f) / (worldSurface * 16.0) * 750.0 + 830.0) + (float)(int)scAdj;
						spriteBatch.Draw(cloudTexture[cloud[i].type], new Vector2(cloud[i].position.X + (float)cloudTexture[cloud[i].type].Width * 0.5f, num3 + (float)cloudTexture[cloud[i].type].Height * 0.5f), new Rectangle(0, 0, cloudTexture[cloud[i].type].Width, cloudTexture[cloud[i].type].Height), color, cloud[i].rotation, new Vector2((float)cloudTexture[cloud[i].type].Width * 0.5f, (float)cloudTexture[cloud[i].type].Height * 0.5f), cloud[i].scale, cloud[i].spriteDir, 0f);
					}
				}
			}
			atmo = 1f;
			bgScale *= 2f;
			bgParrallax = 0.15;
			if (atmo < 1f)
			{
				backColor.R = (byte)((float)(int)backColor.R * atmo);
				backColor.G = (byte)((float)(int)backColor.G * atmo);
				backColor.B = (byte)((float)(int)backColor.B * atmo);
				backColor.A = (byte)((float)(int)backColor.A * atmo);
			}
			if (!mapFullscreen && (double)(screenPosition.Y / 16f) <= worldSurface + 10.0)
			{
				if (owBack)
				{
					if (cloudBGActive > 0f)
					{
						cloudBGAlpha += 0.0005f * (float)dayRate;
						if (cloudBGAlpha > 1f)
						{
							cloudBGAlpha = 1f;
						}
					}
					else
					{
						cloudBGAlpha -= 0.0005f * (float)dayRate;
						if (cloudBGAlpha < 0f)
						{
							cloudBGAlpha = 0f;
						}
					}
					if (cloudBGAlpha > 0f)
					{
						LoadBackground(cloudBG[0]);
						LoadBackground(cloudBG[1]);
						bgScale *= 2f;
						bgParrallax = 0.15;
						float num4 = cloudBGAlpha;
						if (num4 > 1f)
						{
							num4 = 1f;
						}
						bgScale = 1.65f;
						bgParrallax = 0.09000000357627869;
