		protected override void Draw(GameTime gameTime)
		{
			TempRealtimeLogger.Info("Main.Draw", "BEGIN gameMenu=" + gameMenu);
			TimeLogger.NewDrawFrame();
			if (!gameMenu)
			{
				lookForColorTiles();
			}
			TimeLogger.DetailedDrawTime(0);
			if (loadMap)
			{
				refreshMap = false;
				DrawToMap();
				TimeLogger.DetailedDrawTime(1);
			}
			if (Lighting.lightMode >= 2)
			{
				drawToScreen = true;
			}
			else
			{
				drawToScreen = false;
			}
			if (drawToScreen && targetSet)
			{
				ReleaseTargets();
			}
			if (!drawToScreen && !targetSet)
			{
				InitTargets();
			}
			Stopwatch stopwatch = new Stopwatch();
			stopwatch.Start();
			fpsCount++;
			if (!base.IsActive)
			{
				maxQ = true;
			}
			if (!dedServ)
			{
				bool flag = false;
				if (screenWidth != base.GraphicsDevice.Viewport.Width || screenHeight != base.GraphicsDevice.Viewport.Height)
				{
					flag = true;
					mapTime = 0;
					if (gamePaused)
					{
						renderNow = true;
					}
				}
				screenWidth = base.GraphicsDevice.Viewport.Width;
				screenHeight = base.GraphicsDevice.Viewport.Height;
				screenMaximized = ((Form)Control.FromHandle(base.Window.Handle)).WindowState == FormWindowState.Maximized;
				if (!graphics.IsFullScreen)
				{
					if (screenWidth % 2 != 0)
					{
						screenWidth++;
						flag = true;
					}
					if (screenHeight % 2 != 0)
					{
						screenHeight++;
						flag = true;
					}
				}
				if (screenWidth > maxScreenW)
				{
					screenWidth = maxScreenW;
					flag = true;
				}
				if (screenHeight > maxScreenH)
				{
					screenHeight = maxScreenH;
					flag = true;
				}
				if (screenWidth < minScreenW)
				{
					screenWidth = minScreenW;
					flag = true;
				}
				if (screenHeight < minScreenH)
				{
					screenHeight = minScreenH;
					flag = true;
				}
				if (flag)
				{
					graphics.PreferredBackBufferWidth = screenWidth;
					graphics.PreferredBackBufferHeight = screenHeight;
					graphics.ApplyChanges();
					Lighting.Initialize(true);
					if (!drawToScreen)
					{
						InitTargets();
					}
				}
			}
			drawTime++;
			screenLastPosition = screenPosition;
			if (stackSplit == 0)
			{
				stackCounter = 0;
				stackDelay = 7;
				superFastStack = 0;
			}
