		private static void UpdateInvasion()
		{
			if (invasionType <= 0)
			{
				return;
			}
			if (invasionSize <= 0)
			{
				if (invasionType == 1)
				{
					NPC.downedGoblins = true;
					if (netMode == 2)
					{
						NetMessage.SendData(7);
					}
				}
				else if (invasionType == 2)
				{
					NPC.downedFrost = true;
				}
				else if (invasionType == 3)
				{
					NPC.downedPirates = true;
				}
				InvasionWarning();
				invasionType = 0;
				invasionDelay = 7;
			}
			if (invasionX == (double)spawnTileX)
			{
				return;
			}
			float num = dayRate;
			if (invasionX > (double)spawnTileX)
			{
				invasionX -= num;
				if (invasionX <= (double)spawnTileX)
				{
					invasionX = spawnTileX;
					InvasionWarning();
				}
				else
				{
					invasionWarn--;
				}
			}
			else if (invasionX < (double)spawnTileX)
			{
				invasionX += num;
				if (invasionX >= (double)spawnTileX)
				{
					invasionX = spawnTileX;
					InvasionWarning();
				}
				else
				{
					invasionWarn--;
				}
			}
			if (invasionWarn <= 0)
			{
				invasionWarn = 3600;
				InvasionWarning();
			}
		}

		private static void InvasionWarning()
		{
			string text = "";
			text = ((invasionSize <= 0) ? ((invasionType == 2) ? Lang.misc[4] : ((invasionType != 3) ? (text = Lang.misc[0]) : Lang.misc[24])) : ((invasionX < (double)spawnTileX) ? ((invasionType == 2) ? Lang.misc[5] : ((invasionType != 3) ? (text = Lang.misc[1]) : Lang.misc[25])) : ((invasionX > (double)spawnTileX) ? ((invasionType == 2) ? Lang.misc[6] : ((invasionType != 3) ? (text = Lang.misc[2]) : Lang.misc[26])) : ((invasionType == 2) ? Lang.misc[7] : ((invasionType != 3) ? (text = Lang.misc[3]) : Lang.misc[27])))));
			if (netMode == 0)
			{
				NewText(text, 175, 75);
			}
			else if (netMode == 2)
			{
				NetMessage.SendData(25, -1, -1, text, 255, 175f, 75f, 255f);
			}
		}

		public static bool CanStartInvasion(int type = 1, bool ignoreDelay = false)
		{
			if (invasionType != 0)
			{
				return false;
			}
			if (invasionDelay != 0 && !ignoreDelay)
			{
				return false;
			}
			int num = 0;
			for (int i = 0; i < 255; i++)
			{
				if (player[i].active && player[i].statLifeMax >= 200)
				{
					num++;
				}
			}
			return num > 0;
		}

		public static void StartInvasion(int type = 1)
		{
			if (invasionType != 0 || invasionDelay != 0)
			{
				return;
			}
			int num = 0;
			for (int i = 0; i < 255; i++)
			{
				if (player[i].active && player[i].statLifeMax >= 200)
				{
					num++;
				}
			}
			if (num > 0)
			{
				invasionType = type;
				invasionSize = 80 + 40 * num;
				if (type == 3)
				{
					invasionSize += 40 + 20 * num;
				}
				invasionWarn = 0;
				if (rand.Next(2) == 0)
				{
					invasionX = 0.0;
				}
				else
				{
					invasionX = maxTilesX;
				}
			}
		}

		private static void UpdateClient()
		{
			if (myPlayer == 255)
			{
				Netplay.disconnect = true;
			}
			netPlayCounter++;
			if (netPlayCounter > 3600)
			{
				netPlayCounter = 0;
			}
			if (Math.IEEERemainder(netPlayCounter, 420.0) == 0.0)
			{
				NetMessage.SendData(13, -1, -1, "", myPlayer);
			}
			if (Math.IEEERemainder(netPlayCounter, 900.0) == 0.0)
			{
				NetMessage.SendData(36, -1, -1, "", myPlayer);
				NetMessage.SendData(16, -1, -1, "", myPlayer);
				NetMessage.SendData(40, -1, -1, "", myPlayer);
			}
			if (Netplay.clientSock.active)
			{
				Netplay.clientSock.timeOut++;
				if (!stopTimeOuts && Netplay.clientSock.timeOut > 60 * timeOut)
				{
					statusText = Lang.inter[43];
					Netplay.disconnect = true;
				}
			}
			for (int i = 0; i < 400; i++)
			{
				if (item[i].active && item[i].owner == myPlayer)
				{
					item[i].FindOwner(i);
				}
			}
		}

		private static void UpdateServer()
		{
			netPlayCounter++;
			if (netPlayCounter > 3600)
			{
				NetMessage.SendData(7);
				NetMessage.syncPlayers();
				netPlayCounter = 0;
			}
			for (int i = 0; i < maxNetPlayers; i++)
			{
				if (player[i].active && Netplay.serverSock[i].active)
				{
					Netplay.serverSock[i].SpamUpdate();
				}
			}
			if (Math.IEEERemainder(netPlayCounter, 900.0) == 0.0)
			{
				bool flag = true;
				int num = lastItemUpdate;
				int num2 = 0;
				while (flag)
				{
					num++;
					if (num >= 400)
					{
						num = 0;
					}
					num2++;
					if (!item[num].active || item[num].owner == 255)
					{
						NetMessage.SendData(21, -1, -1, "", num);
					}
					if (num2 >= maxItemUpdates || num == lastItemUpdate)
					{
						flag = false;
					}
				}
				lastItemUpdate = num;
			}
			for (int j = 0; j < 400; j++)
			{
				if (item[j].active && (item[j].owner == 255 || !player[item[j].owner].active))
				{
					item[j].FindOwner(j);
				}
			}
			for (int k = 0; k < 255; k++)
			{
				if (Netplay.serverSock[k].active)
				{
					Netplay.serverSock[k].timeOut++;
					if (!stopTimeOuts && Netplay.serverSock[k].timeOut > 60 * timeOut)
					{
						Netplay.serverSock[k].kill = true;
					}
				}
				if (player[k].active)
				{
					ServerSock.CheckSection(k, player[k].position);
				}
			}
		}

		public static void NewText(string newText, byte R = byte.MaxValue, byte G = byte.MaxValue, byte B = byte.MaxValue, bool force = false)
		{
			int num = 80;
			if (!force && newText.Length > num)
			{
				string text = newText;
				while (text.Length > num)
				{
					int num2 = num;
					int num3 = num2;
					while (text.Substring(num3, 1) != " ")
					{
						num3--;
						if (num3 < 1)
						{
							break;
						}
					}
					if (num3 == 0)
					{
						while (text.Substring(num2, 1) != " ")
						{
							num2++;
							if (num2 >= text.Length - 1)
							{
								break;
							}
						}
					}
					else
					{
						num2 = num3;
					}
					if (num2 >= text.Length - 1)
					{
						num2 = text.Length;
					}
					string newText2 = text.Substring(0, num2);
					NewText(newText2, R, G, B, true);
					text = text.Substring(num2);
					if (text.Length > 0)
					{
						while (text.Substring(0, 1) == " ")
						{
							text = text.Substring(1);
						}
					}
				}
				if (text.Length > 0)
				{
					NewText(text, R, G, B, true);
				}
			}
			else
			{
				for (int num4 = numChatLines - 1; num4 > 0; num4--)
				{
					chatLine[num4].text = chatLine[num4 - 1].text;
					chatLine[num4].showTime = chatLine[num4 - 1].showTime;
					chatLine[num4].color = chatLine[num4 - 1].color;
				}
				if (R == 0 && G == 0 && B == 0)
				{
					chatLine[0].color = Color.White;
				}
				else
				{
					chatLine[0].color = new Color(R, G, B);
				}
				chatLine[0].text = newText;
				chatLine[0].showTime = chatLength;
				PlaySound(12);
			}
		}

		private static void StopRain()
		{
			rainTime = 0;
			raining = false;
			maxRaining = 0f;
		}

		private static void StartRain()
		{
			int num = 86400;
			int num2 = num / 24;
			rainTime = rand.Next(num2 * 8, num);
			if (rand.Next(3) == 0)
			{
				rainTime += rand.Next(0, num2);
			}
			if (rand.Next(4) == 0)
			{
				rainTime += rand.Next(0, num2 * 2);
			}
			if (rand.Next(5) == 0)
			{
				rainTime += rand.Next(0, num2 * 2);
			}
			if (rand.Next(6) == 0)
			{
				rainTime += rand.Next(0, num2 * 3);
			}
			if (rand.Next(7) == 0)
			{
				rainTime += rand.Next(0, num2 * 4);
			}
			if (rand.Next(8) == 0)
			{
				rainTime += rand.Next(0, num2 * 5);
			}
			float num3 = 1f;
			if (rand.Next(2) == 0)
			{
				num3 += 0.05f;
			}
			if (rand.Next(3) == 0)
			{
				num3 += 0.1f;
			}
			if (rand.Next(4) == 0)
			{
				num3 += 0.15f;
			}
			if (rand.Next(5) == 0)
			{
				num3 += 0.2f;
			}
			rainTime = (int)((float)rainTime * num3);
			ChangeRain();
			raining = true;
		}

		private static void ChangeRain()
		{
			if (cloudBGActive >= 1f || (double)numClouds > 150.0)
			{
				if (rand.Next(3) == 0)
				{
					maxRaining = (float)rand.Next(20, 90) * 0.01f;
				}
				else
				{
					maxRaining = (float)rand.Next(40, 90) * 0.01f;
				}
			}
			else if ((double)numClouds > 100.0)
			{
				if (rand.Next(3) == 0)
				{
					maxRaining = (float)rand.Next(10, 70) * 0.01f;
				}
				else
				{
					maxRaining = (float)rand.Next(20, 60) * 0.01f;
				}
			}
			else if (rand.Next(3) == 0)
			{
				maxRaining = (float)rand.Next(5, 40) * 0.01f;
			}
			else
			{
				maxRaining = (float)rand.Next(5, 30) * 0.01f;
			}
		}

		private static void UpdateTime()
		{
			if (pumpkinMoon)
			{
				bloodMoon = false;
				snowMoon = false;
			}
			if (snowMoon)
			{
				bloodMoon = false;
			}
			if ((netMode != 1 && !gameMenu) || netMode == 2)
			{
				if (raining)
				{
					rainTime -= dayRate;
					int num = 86400;
					num /= dayRate;
					int num2 = num / 24;
					if (rainTime <= 0)
					{
						StopRain();
					}
					else if (rand.Next(num2 * 2) == 0)
					{
						ChangeRain();
					}
				}
				else
				{
					int num3 = 86400;
					num3 /= ((dayRate == 0) ? 1 : dayRate);
					if (rand.Next((int)((double)num3 * 5.5)) == 0)
					{
						StartRain();
					}
					else if (cloudBGActive >= 1f && rand.Next(num3 * 4) == 0)
					{
						StartRain();
					}
				}
			}
			if (maxRaining != oldMaxRaining)
			{
				if (netMode == 2)
				{
					NetMessage.SendData(7);
				}
				oldMaxRaining = maxRaining;
			}
			time += dayRate;
			if (netMode != 1)
			{
				if (NPC.travelNPC)
				{
					if (!dayTime || time > 48600.0)
					{
						WorldGen.UnspawnTravelNPC();
					}
				}
				else if (dayTime && time < 27000.0)
				{
					int num4 = (int)(27000.0 / (double)dayRate);
					num4 *= 4;
					if (rand.Next(num4) == 0)
					{
						int num5 = 0;
						for (int i = 0; i < 200; i++)
						{
							if (npc[i].active && npc[i].townNPC && npc[i].type != 37)
							{
								num5++;
							}
						}
						if (num5 >= 2)
						{
							WorldGen.SpawnTravelNPC();
						}
					}
				}
				NPC.travelNPC = false;
			}
			if (!dayTime)
			{
				eclipse = false;
				if (WorldGen.spawnEye && netMode != 1 && time > 4860.0)
				{
					for (int j = 0; j < 255; j++)
					{
						if (player[j].active && !player[j].dead && (double)player[j].position.Y < worldSurface * 16.0)
						{
							NPC.SpawnOnPlayer(j, 4);
							WorldGen.spawnEye = false;
							break;
						}
					}
				}
				if (WorldGen.spawnHardBoss > 0 && netMode != 1 && time > 4860.0)
				{
					bool flag = false;
					for (int k = 0; k < 200; k++)
					{
						if (npc[k].active && npc[k].boss)
						{
							flag = true;
						}
					}
					if (!flag)
					{
						for (int l = 0; l < 255; l++)
						{
							if (player[l].active && !player[l].dead && (double)player[l].position.Y < worldSurface * 16.0)
							{
								if (WorldGen.spawnHardBoss == 1)
								{
									NPC.SpawnOnPlayer(l, 134);
								}
								else if (WorldGen.spawnHardBoss == 2)
								{
									NPC.SpawnOnPlayer(l, 125);
									NPC.SpawnOnPlayer(l, 126);
								}
								else if (WorldGen.spawnHardBoss == 3)
								{
									NPC.SpawnOnPlayer(l, 127);
								}
								break;
							}
						}
					}
					WorldGen.spawnHardBoss = 0;
				}
				if (time > 32400.0)
				{
					checkXMas();
					checkHalloween();
					AnglerQuestSwap();
					if (invasionDelay > 0)
					{
						invasionDelay--;
					}
					WorldGen.spawnNPC = 0;
					checkForSpawns = 0;
					time = 0.0;
					bloodMoon = false;
					stopMoonEvent();
					dayTime = true;
					moonPhase++;
					if (moonPhase >= 8)
					{
						moonPhase = 0;
					}
					if (netMode == 2)
					{
						NetMessage.SendData(7);
						WorldGen.saveAndPlay();
					}
					if (netMode != 1)
					{
						if (WorldGen.shadowOrbSmashed)
						{
							if (!NPC.downedGoblins)
							{
								if (rand.Next(3) == 0)
								{
									StartInvasion();
								}
							}
							else if ((hardMode && rand.Next(60) == 0) || (!hardMode && rand.Next(30) == 0))
							{
								StartInvasion();
							}
						}
						if (invasionType == 0 && hardMode && WorldGen.altarCount > 0 && ((NPC.downedPirates && rand.Next(50) == 0) || (!NPC.downedPirates && rand.Next(30) == 0)))
						{
							StartInvasion(3);
						}
					}
					if (hardMode && NPC.downedMechBossAny && rand.Next(25) == 0 && netMode != 1)
					{
						eclipse = true;
						if (eclipse)
						{
							if (netMode == 0)
							{
								NewText(Lang.misc[20], 50, byte.MaxValue, 130);
							}
							else if (netMode == 2)
							{
								NetMessage.SendData(25, -1, -1, Lang.misc[20], 255, 50f, 255f, 130f);
							}
						}
						if (netMode == 2)
						{
							NetMessage.SendData(7);
						}
					}
				}
				if (time > 16200.0 && WorldGen.spawnMeteor)
				{
					WorldGen.spawnMeteor = false;
					WorldGen.dropMeteor();
				}
				return;
			}
			bloodMoon = false;
			stopMoonEvent();
			if (time > 54000.0)
			{
				NPC.setFireFlyChance();
				WorldGen.spawnNPC = 0;
				checkForSpawns = 0;
				if (rand.Next(50) == 0 && netMode != 1 && WorldGen.shadowOrbSmashed)
				{
					WorldGen.spawnMeteor = true;
				}
				eclipse = false;
				if (!NPC.downedBoss1 && netMode != 1)
				{
					bool flag2 = false;
					for (int m = 0; m < 255; m++)
					{
						if (player[m].active && player[m].statLifeMax >= 200 && player[m].statDefense > 10)
						{
							flag2 = true;
							break;
						}
					}
					if (flag2 && rand.Next(3) == 0)
					{
						int num6 = 0;
						for (int n = 0; n < 200; n++)
						{
							if (npc[n].active && npc[n].townNPC)
							{
								num6++;
							}
						}
						if (num6 >= 4)
						{
